import React, { useState } from "react";
import {
  ComposedChart,
  Line,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ReferenceLine,
  Area,
} from "recharts";

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{
      background: "var(--bg-elevated)",
      border: "1px solid var(--border)",
      padding: "10px 14px",
      borderRadius: "6px",
      fontSize: "12px",
      fontFamily: "var(--font-mono)",
    }}>
      <div style={{ color: "var(--text-secondary)", marginBottom: "6px" }}>{label}</div>
      {payload.map((p) => (
        <div key={p.name} style={{ color: p.color, marginBottom: "2px" }}>
          {p.name}: {typeof p.value === "number" ? p.value.toFixed(2) : p.value}
        </div>
      ))}
    </div>
  );
};

export default function PriceChart({ data, forecast }) {
  const [showMA, setShowMA] = useState(true);

  if (!data) return null;

  const chartData = data.dates.map((d, i) => ({
    date: d.slice(5),
    Price: data.prices[i],
    MA20: data.ma20[i],
    Volume: data.volume[i],
  }));

  if (forecast) {
    forecast.dates.forEach((d, i) => {
      chartData.push({
        date: d.slice(5),
        Forecast: forecast.prices[i],
        isForecast: true,
      });
    });
  }

  return (
    <div>
      <div style={{ display: "flex", gap: "12px", marginBottom: "16px" }}>
        <button
          onClick={() => setShowMA(!showMA)}
          style={{
            background: showMA ? "var(--accent-blue-dim)" : "transparent",
            border: `1px solid ${showMA ? "var(--accent-blue)" : "var(--border)"}`,
            color: showMA ? "var(--accent-blue)" : "var(--text-dim)",
            padding: "4px 12px",
            fontFamily: "var(--font-mono)",
            fontSize: "11px",
            borderRadius: "3px",
            cursor: "pointer",
          }}
        >
          MA20
        </button>
      </div>

      <ResponsiveContainer width="100%" height={280}>
        <ComposedChart data={chartData} margin={{ top: 4, right: 4, left: 4, bottom: 4 }}>
          <XAxis
            dataKey="date"
            tick={{ fill: "var(--text-dim)", fontSize: 10, fontFamily: "var(--font-mono)" }}
            tickLine={false}
            axisLine={{ stroke: "var(--border)" }}
            interval={19}
          />
          <YAxis
            yAxisId="price"
            tick={{ fill: "var(--text-dim)", fontSize: 10, fontFamily: "var(--font-mono)" }}
            tickLine={false}
            axisLine={false}
            width={70}
            tickFormatter={(v) => v?.toFixed(0)}
          />
          <YAxis
            yAxisId="vol"
            orientation="right"
            tick={false}
            axisLine={false}
            width={0}
          />
          <Tooltip content={<CustomTooltip />} />

          <Bar yAxisId="vol" dataKey="Volume" fill="#38bdf808" barSize={3} />

          <Area
            yAxisId="price"
            type="monotone"
            dataKey="Price"
            stroke="var(--accent-blue)"
            strokeWidth={1.5}
            fill="var(--accent-blue-dim)"
            dot={false}
            activeDot={{ r: 3 }}
          />

          {showMA && (
            <Line
              yAxisId="price"
              type="monotone"
              dataKey="MA20"
              stroke="#ffd60a"
              strokeWidth={1}
              dot={false}
              strokeDasharray="4 2"
            />
          )}

          <Line
            yAxisId="price"
            type="monotone"
            dataKey="Forecast"
            stroke="var(--accent-green)"
            strokeWidth={2}
            dot={{ fill: "var(--accent-green)", r: 4 }}
            strokeDasharray="6 3"
            connectNulls={false}
          />
        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
}
